int myInt = 9;
double myDouble = myInt; // automatic widening: int -> double
System.out.println(myDouble); // 9.0

double myDouble = 9.78;
int myInt = (int) myDouble; // explicit narrowing: double -> int
System.out.println(myInt); // 9

int a = 5;
int b = 2;

System.out.println(a / b);          // 2 — int / int stays int
System.out.println((double) a / b); // 2.5 — a is cast to double first

int big = 130;
byte small = (byte) big;
System.out.println(small); // -126 (not 130!)

char letter = 'A';
int code = letter; // widening: char -> int, automatic
System.out.println(code); // 65

int num = 66;
char back = (char) num; // narrowing: int -> char, needs a cast
System.out.println(back); // B

public class Main {
    public static void main(String[] args) {
        int total = 7;
        int count = 2;

        double average = (double) total / count;
        System.out.println("Average: " + average);

        double price = 49.99;
        int roundedDownPrice = (int) price;
        System.out.println("Rounded down price: " + roundedDownPrice);
    }
}

